const localVersion = '5.4.8';

let controlUrl = host[0];

function login(flag) {
    if (flag == undefined) {
        result = JSON.parse(source.getLoginInfo())
    } else {
        java.longToast("\n\nрҹ’һжӯЈеңЁзҷ»еҪ•дёӯ...")
        putLoginInfo(JSON.stringify(result))
    }
    let base_url = getArgument('server')
    let zdyserver = String(result['иҮӘе®ҡд№үжңҚеҠЎеҷЁ(еҸҜдёҚеЎ«)']);
    if (zdyserver.includes('http')) {
        setArgument('server', zdyserver);
        if (getKey(String(cookie.getCookie(base_url)))) {
            let cookies = cookie.getCookie(base_url)
            try {
                cookie.removeCookie(base_url)
            } catch (e) {}
            cookie.setCookie(zdyserver, cookies)
        }
        java.toast(`\n\nеҪ“еүҚжңҚеҠЎеҷЁдёәиҮӘе®ҡд№үжңҚеҠЎеҷЁ\n${zdyserver}\n\nеҲҮжҚўжңҚеҠЎеҷЁиҜ·е…Ҳжё…з©әжңҚеҠЎеҷЁең°еқҖдёӯзҡ„ж•°жҚ®`);
    }
    let plcolor = String(getArgument('plcolor') || result['иҮӘе®ҡд№үиҜ„и®әйўңиүІ(еҸҜдёҚеЎ«)'] || '#000000');
    if (plcolor) {
        setArgument('plcolor', plcolor);
    } else {
        setArgument('plcolor', '#000000');
    }
    let zdysources = String(result['иҮӘе®ҡд№үжҗңзҙўжәҗ(еӨҡдёӘз”ЁиӢұж–Ү,еҲҶеүІ)'] || '');
    if (zdysources) {
        setArgument('sources', zdysources);
    };
    base_url = getArgument('server')
    let register_email = String(result['йӮ®з®ұ'])
    let password = String(result['еҜҶз Ғ'])
    let key = String(result['еҜҶй’Ҙ'] || '')

    if ((register_email && password || key) && !String(getKey(String(cookie.getCookie(base_url))))) {
        try {
            cookie.removeCookie(base_url)
        } catch (e) {}
        let deviceKey = '';
        try {
            deviceKey = java.deviceID();
        } catch (e) {
            deviceKey = java.androidId();
        };
