                body: JSON.stringify({
                    register_email: result['йӮ®з®ұ'],
                    password: result['еҜҶз Ғ']
                })
            })
            try {
                let data = JSON.parse(java.ajax(`${base_url}/login_api,${options}`))
                if (data.code == 0) {
                    //java.toast(deviceId)
                    java.toast("\n\nвң…пёҸзҷ»еҪ•жҲҗеҠҹ")
                    cookie.setCookie(base_url, `qttoken=${data.key};deviceId=${deviceId}`)
                    result['еҜҶй’Ҙ'] = data.key
                    putLoginInfo(JSON.stringify(result))
                } else {
                    java.toast('\n\nрҹ’”' + data.msg || "зҷ»еҪ•еӨұиҙҘпјҢиҜ·йҮҚиҜ•пјҒ")
