                java.toast("\n\nрҹ’”зҷ»еҪ•еӨұиҙҘпјҢиҜ·йҮҚиҜ•пјҒ\n" + e.message)
            }
        } else {
            cookie.setCookie(base_url, `qttoken=${key};deviceId=${deviceId}`)
            let res = java.ajax(`${base_url}/user_api,{"method":"POST","headers":{"cookie":"${cookie.getCookie(base_url)}"}}`)
            try {
                res = JSON.parse(res)
                if (res.id != undefined) {
                    java.toast('\n\nеҜҶй’Ҙзҷ»еҪ•жҲҗеҠҹ')
                    result['йӮ®з®ұ'] = res.email
                    putLoginInfo(JSON.stringify(result))
                } else {
                    throw new Error()
                }
            } catch (e) {
                java.log(e)
                java.toast("\n\nрҹ’”зҷ»еҪ•еӨұиҙҘ")
            }
        }
    } else if (flag && String(getKey(String(cookie.getCookie(base_url))))) {
        java.toast("\n\nеҪ“еүҚвң…пёҸе·Ізҷ»еҪ•пјҢиҜ·рҹҡ«йҖҖеҮәзҷ»еҪ•еҗҺйҮҚж–°зҷ»еҪ•");
