function set_media(media) {
    const mediaConfig = {
        'е–ңй©¬жӢүйӣ…': ['еҗ¬д№Ұ'],
        'з•ӘиҢ„': '*',
        'зҰҸеҲ©е°ҸиҜҙ':['е°ҸиҜҙ'],
