        'жј«з”»зҪ‘':['жј«з”»'],
        'йЈҺиҪҰжј«з”»':['жј«з”»'],
        'зҰҸеҲ©жј«з”»':['жј«з”»'],
        'еҘҪзңӢжј«з”»':['жј«з”»'],
        'й…·жҲ‘':['еҗ¬д№Ұ'],
        'жө·жҙӢеҗ¬д№Ұ':['еҗ¬д№Ұ'],
        'дёғзҢ«': ['е°ҸиҜҙ', 'еҗ¬д№Ұ'],
