        'й»ҳи®Ө': ['е°ҸиҜҙ']
    };

    const source = getArgument('source');
    const allowedModes = mediaConfig[source] || mediaConfig['й»ҳи®Ө'];
    let targetMedia = mediaConfig['й»ҳи®Ө'][0];
    let isAllowed = false;

    if (allowedModes === '*' || allowedModes.includes(media)) {
        targetMedia = media;
        isAllowed = true;
    } else if (Array.isArray(allowedModes)) {
        targetMedia = allowedModes[0];
