      width: 50px;
      height: 50px;
      border: 4px solid rgba(78, 110, 242, 0.3);
      border-top-color: #4e6ef2;
      border-radius: 50%;
      margin: 0 auto 20px;
      animation: spin 1s linear infinite;
    }

    .loading-text {
      color: var(--text-main);
      font-size: 16px;
      font-weight: 500;
    }

    @keyframes spin {
      to { transform: rotate(360deg); }
    }

    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }

    @keyframes slideIn {
      from { opacity: 0; transform: translateY(30px); }
      to { opacity: 1; transform: translateY(0); }
    }

    @keyframes pulse {
      0%, 100% { opacity: 1; }
      50% { opacity: 0.7; }
    }

    @keyframes gradientAnimation {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }

    @keyframes breathe {
      0%, 100% { 
        transform: scale(1);
        box-shadow: var(--glow-shadow), var(--shadow);
      }
      50% { 
        transform: scale(1.02);
        box-shadow: 0 0 30px rgba(142, 45, 226, 0.6), 0 0 60px rgba(212, 175, 55, 0.4), var(--shadow);
      }
    }

    @keyframes shimmer {
      0% {
        background-position: -200% center;
      }
      100% {
        background-position: 200% center;
      }
    }

    /* дё»е®№еҷЁ */
    .container {
      width: 100%;
      max-width: 420px;
      background: var(--card-bg);
      border-radius: 24px;
      overflow: hidden;
      box-shadow: var(--shadow);
      position: relative;
      z-index: 1;
      animation: slideIn 0.5s ease;
      display: none;
    }

    /* еӨҙйғЁ */
    .header {
      background: var(--primary-gradient);
      color: #ffffff;
      padding: 24px 16px;
      text-align: center;
      position: relative;
      overflow: hidden;
    }

    .header::before {
      content: '';
      position: absolute;
      top: -30px;
      left: -30px;
      width: 80px;
      height: 80px;
      background: rgba(255, 255, 255, 0.15);
      border-radius: 50%;
    }

    .header::after {
      content: '';
      position: absolute;
      bottom: -60px;
      right: -60px;
      width: 150px;
      height: 150px;
      background: rgba(255, 255, 255, 0.1);
      border-radius: 50%;
    }

    .header h1 {
      font-size: 1.4rem;
      font-weight: 700;
      margin-bottom: 8px;
      position: relative;
      z-index: 2;
    }

    .header p {
      font-size: 0.9rem;
      opacity: 0.9;
      line-height: 1.4;
      position: relative;
      z-index: 2;
    }

    .header-icon {
      font-size: 48px;
      margin-bottom: 10px;
      display: inline-block;
      animation: bounce 2s ease infinite;
    }

    @keyframes bounce {
      0%, 100% { transform: translateY(0); }
      50% { transform: translateY(-10px); }
    }

    /* зүҲжң¬еҜ№жҜ” */
    .version-comparison {
      display: flex;
      flex-wrap: nowrap;
      gap: 12px;
      padding: 16px;
      margin-top: 8px;
      position: relative;
      z-index: 10;
