    }

    .version-date {
      font-size: 0.8rem;
      color: var(--text-secondary);
      margin-top: 4px;
    }

    /* зүҲжң¬еҜ№жҜ”жҢҮзӨәеҷЁ */
    .version-indicator {
      position: absolute;
      left: 50%;
      top: 50%;
      transform: translate(-50%, -50%);
      z-index: 5;
      width: 32px;
      height: 32px;
