    .update-header {
      background: var(--light-bg);
      padding: 12px 16px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid var(--border-color);
    }

    .update-header h2 {
      font-size: 1rem;
      font-weight: 600;
      color: var(--text-main);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .update-header h2 i {
      color: #4e6ef2;
    }

    .update-tag {
      background: rgba(78, 110, 242, 0.1);
      color: #4e6ef2;
      padding: 4px 8px;
