      color: var(--text-main);
      font-size: 0.95rem;
      white-space: pre-wrap;
      word-break: break-word;
    }

    .update-text::before {
      content: 'вҖў';
      position: absolute;
      left: 0;
      font-weight: bold;
      color: #4e6ef2;
      font-size: 1.2rem;
      line-height: 1;
    }

    /* еҺҶеҸІж—Ҙеҝ— */
    .history-container {
      background: var(--card-bg);
      border-radius: 16px;
      box-shadow: var(--shadow);
      margin-bottom: 16px;
      border: 1px solid rgba(120, 130, 240, 0.1);
      animation: slideIn 0.5s ease 0.5s backwards;
    }

    .history-header {
      background: var(--light-bg);
      padding: 12px 16px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid var(--border-color);
      cursor: pointer;
      user-select: none;
    }

    .history-header:hover {
      opacity: 0.8;
    }

    .history-header h2 {
      font-size: 1rem;
      font-weight: 600;
      color: var(--text-main);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .history-header h2 i {
      color: #4e6ef2;
    }

    .toggle-history {
      background: none;
      border: none;
      color: var(--text-secondary);
      cursor: pointer;
      font-weight: 500;
      display: flex;
      align-items: center;
      gap: 4px;
      font-size: 0.85rem;
      transition: color 0.2s ease;
    }

    .toggle-history:hover {
      color: #4e6ef2;
    }

    .history-content {
      padding: 0 16px;
      max-height: 0;
      overflow: hidden;
      transition: max-height 0.4s ease, padding 0.4s ease;
    }

    .history-content.expanded {
      max-height: 60vh;
      overflow-y: auto;
      padding: 16px;
      scrollbar-width: thin;
      scrollbar-color: #4e6ef2 #f0f0f0;
    }

    .history-content.expanded::-webkit-scrollbar {
      width: 6px;
    }

    .history-content.expanded::-webkit-scrollbar-track {
      background: #f0f0f0;
      border-radius: 4px;
    }

    .history-content.expanded::-webkit-scrollbar-thumb {
      background: #4e6ef2;
      border-radius: 4px;
    }

    .history-content.expanded::-webkit-scrollbar-thumb:hover {
      background: #3a56d0;
    }

    .history-item {
      margin-bottom: 16px;
      padding-bottom: 16px;
      border-bottom: 1px dashed var(--border-color);
    }

    .history-item:last-child {
      border-bottom: none;
      margin-bottom: 0;
      padding-bottom: 0;
    }

    .history-date {
      font-weight: 600;
      color: var(--text-main);
      margin-bottom: 8px;
      display: flex;
      align-items: center;
      gap: 4px;
      font-size: 0.9rem;
      background: rgba(78, 110, 242, 0.05);
      padding: 6px 10px;
      border-radius: 6px;
    }

    .history-text {
      margin: 8px 0;
      padding-left: 16px;
      line-height: 1.4;
      color: var(--text-secondary);
      position: relative;
      font-size: 0.9rem;
      white-space: pre-wrap;
      word-break: break-word;
    }

    .history-text::before {
      content: 'вҖў';
      position: absolute;
      left: 0;
      color: #4e6ef2;
      font-weight: bold;
      font-size: 1.2rem;
      line-height: 1;
    }

    /* жҢүй’®з»„ */
    .button-group {
      display: flex;
      flex-direction: column;
      gap: 10px;
      margin-bottom: 16px;
    }

    .button {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 10px;
      padding: 14px 28px;
      text-align: center;
      font-size: 1rem;
      border: none;
      border-radius: 12px;
      text-decoration: none;
      background: var(--primary-gradient);
      color: white;
      font-weight: 600;
      transition: all 0.3s ease;
      box-shadow: var(--shadow);
      position: relative;
      overflow: hidden;
      cursor: pointer;
    }

    .button i {
      font-size: 1rem;
    }

    .button::after {
      content: '';
      position: absolute;
      top: -50%;
      left: -50%;
      width: 200%;
      height: 200%;
      background: rgba(255, 255, 255, 0.1);
      transform: rotate(30deg);
      transition: all 0.6s ease;
      pointer-events: none;
    }

    .button:hover {
      transform: translateY(-3px);
      box-shadow: var(--shadow-hover);
    }

    .button:hover::after {
      transform: rotate(30deg) translate(20%, 20%);
    }

    .button:active {
      transform: scale(0.95);
    }

    /* й”ҷиҜҜзҠ¶жҖҒ */
    .error-state {
      text-align: center;
      padding: 40px 20px;
      color: var(--text-main);
    }

    .error-icon {
      font-size: 64px;
      margin-bottom: 20px;
      color: var(--error-color);
    }

    .error-text {
      font-size: 16px;
      line-height: 1.6;
      margin-bottom: 20px;
    }

    .retry-button {
      background: var(--primary-gradient);
      color: white;
      padding: 12px 30px;
      border-radius: 12px;
      border: none;
      font-weight: 600;
      cursor: pointer;
      transition: all 0.3s ease;
      font-size: 14px;
      box-shadow: var(--shadow);
    }

    .retry-button:hover {
      transform: translateY(-2px);
      box-shadow: var(--shadow-hover);
    }

    .retry-button:active {
      transform: scale(0.95);
    }

    /* иЈ…йҘ°е…ғзҙ  */
    .decoration {
      position: absolute;
      z-index: 0;
      pointer-events: none;
    }

    .decoration.circle {
      width: 120px;
      height: 120px;
      border-radius: 50%;
      background: rgba(107, 45, 216, 0.05);
      top: 10%;
      left: 10%;
    }

    .decoration.square {
      width: 80px;
      height: 80px;
      transform: rotate(45deg);
      background: rgba(78, 110, 242, 0.05);
      bottom: 10%;
      right: 10%;
    }

    /* е“Қеә”ејҸ */
    @media (max-width: 768px) {
      body {
        padding: 12px;
      }

      .container {
        max-width: 100%;
        border-radius: 20px;
      }

